// Build Prompt for OpenAI — with user account context
const https = require('https');
const body = $input.first().json.body;
const question = body.question || '';
const history = body.history || [];
const lang = body.lang || 'es';
const token = body.token || '';
const appContext = body.appContext || '';

// Verify token and get user info
let userInfo = null;
if (token) {
  try {
    const postData = JSON.stringify({ token });
    const result = await new Promise((resolve, reject) => {
      const req = https.request({
        hostname: 'prometeix-servidor-n8n.reyl9a.easypanel.host',
        port: 443, path: '/webhook/auth-verify', method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(postData) }
      }, (res) => {
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => {
          try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
          catch(e) { resolve(null); }
        });
      });
      req.on('error', () => resolve(null));
      req.setTimeout(5000, () => { req.destroy(); resolve(null); });
      req.write(postData);
      req.end();
    });
    if (result && result.success) userInfo = result;
  } catch(e) { /* ignore */ }
}

const userContext = userInfo ? `

## Datos de la cuenta del usuario actual
- Nombre: ${userInfo.name || 'No disponible'}
- Email: ${userInfo.email || 'No disponible'}
- Empresa: ${userInfo.company || 'No especificada'}
- Rol: ${userInfo.role === 'marketplace_admin' ? 'Administrador' : userInfo.role === 'seller' ? 'Vendedor' : userInfo.role || 'Usuario'}
- Marketplace: ${userInfo.marketplace_id || 'No especificado'}
- Estado de suscripción: ${userInfo.subscription_status === 'active' ? 'Activa' : userInfo.subscription_status === 'trialing' ? 'En periodo de prueba' : userInfo.subscription_status || 'No disponible'}
- Idioma: ${userInfo.lang === 'pt' ? 'Portugués' : 'Español'}

Cuando el usuario pregunte por datos de su cuenta, usa esta información para responder directamente.` : '';

const userContextPT = userInfo ? `

## Dados da conta do utilizador atual
- Nome: ${userInfo.name || 'Não disponível'}
- Email: ${userInfo.email || 'Não disponível'}
- Empresa: ${userInfo.company || 'Não especificada'}
- Função: ${userInfo.role === 'marketplace_admin' ? 'Administrador' : userInfo.role === 'seller' ? 'Vendedor' : userInfo.role || 'Utilizador'}
- Marketplace: ${userInfo.marketplace_id || 'Não especificado'}
- Estado da subscrição: ${userInfo.subscription_status === 'active' ? 'Ativa' : userInfo.subscription_status === 'trialing' ? 'Em período de teste' : userInfo.subscription_status || 'Não disponível'}
- Idioma: ${userInfo.lang === 'pt' ? 'Português' : 'Espanhol'}

Quando o utilizador perguntar sobre dados da sua conta, use esta informação para responder diretamente.` : '';

