const response = $input.first().json;
let answer = '';

try {
  if (response.choices && response.choices.length > 0) {
    answer = response.choices[0].message.content || '';
  } else {
    answer = 'Lo siento, no pude procesar tu consulta. Por favor, inténtalo de nuevo o contacta soporte en info@katalync.com.';
  }
} catch (e) {
  answer = 'Lo siento, ha ocurrido un error. Por favor, inténtalo de nuevo o contacta soporte en info@katalync.com.';
}

return [{
  json: {
    answer
  }
}];

